using System;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Faktorial hesablanır...");
        int result = CalculateFactorial(5);
        Console.WriteLine($"5! = {result}");
    }

    static int CalculateFactorial(int n)
    {
        // Əsas şərt
        if (n <= 1)
            return 1;
        // Rekursiv çağırış
        return n * CalculateFactorial(n - 1);
    }
}
// Output:
// Faktorial hesablanır...
// 5! = 120

using System;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Fibonacci sayı hesablanır...");
        int result = CalculateFibonacci(6);
        Console.WriteLine($"Fibonacci(6) = {result}");
    }

    static int CalculateFibonacci(int n)
    {
        // Əsas şərt
        if (n <= 1)
            return n;
        // Rekursiv çağırış
        return CalculateFibonacci(n - 1) + CalculateFibonacci(n - 2);
    }
}
// Output:
// Fibonacci sayı hesablanır...
// Fibonacci(6) = 8

using System;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Faktorial (quyruq rekursiyası) hesablanır...");
        int result = CalculateFactorialTail(5, 1);
        Console.WriteLine($"5! = {result}");
    }

    static int CalculateFactorialTail(int n, int accumulator)
    {
        // Əsas şərt
