using System;

class Program
{
    static void Main(string[] args)
    {
        try
        {
            Console.WriteLine("Faktorial hesablanır...");
            int result = CalculateFactorial(-1);
            Console.WriteLine($"Nəticə: {result}");
        }
        catch (ArgumentException ex)
        {
            Console.WriteLine("Səhv baş verdi!");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
